1	export type Cell = [number, number];
2	
3	const toKey = ([x, y]: Cell): string => `${x},${y}`;
4	
5	const fromKey = (key: string): Cell => {
6	  const [x, y] = key.split(",").map(Number);
7	  return [x, y];
8	};
9	
10	const survives = (neighborCount: number, isAlive: boolean): boolean =>
11	  neighborCount === 3 || (neighborCount === 2 && isAlive);
12	
13	export const nextGeneration = (cells: Cell[]): Cell[] => {
14	  const aliveKeys = new Set(cells.map(toKey));
15	  const neighborCounts = new Map<string, number>();
16	
17	  for (const [x, y] of cells) {
18	    for (let dx = -1; dx <= 1; dx++) {
19	      for (let dy = -1; dy <= 1; dy++) {
20	        if (dx === 0 && dy === 0) continue;
21	        const key = toKey([x + dx, y + dy]);
22	        neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
23	      }
24	    }
25	  }
26	
27	  const result: Cell[] = [];
28	  for (const [key, count] of neighborCounts) {
29	    if (survives(count, aliveKeys.has(key))) {
30	      result.push(fromKey(key));
31	    }
32	  }
33	  return result;
34	};
