1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("returns empty array when given empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("kills a single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("kills two adjacent live cells (each has 1 neighbor, underpopulation)", () => {
12	    expect(nextGeneration([[0, 0], [1, 0]])).toEqual([]);
13	  });
14	  it("keeps a block (2x2) alive unchanged (still life)", () => {
15	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result).toHaveLength(4);
18	    expect(new Set(result.map(c => c.join(",")))).toEqual(
19	      new Set(block.map(c => c.join(",")))
20	    );
21	  });
22	  it("transforms a vertical blinker into a horizontal blinker", () => {
23	    const vertical: [number, number][] = [[0, 0], [0, 1], [0, 2]];
24	    const result = nextGeneration(vertical);
25	    expect(result).toHaveLength(3);
26	    expect(new Set(result.map(c => c.join(",")))).toEqual(
27	      new Set([[-1, 1], [0, 1], [1, 1]].map(c => c.join(",")))
28	    );
29	  });
30	  it("brings a dead cell to life when it has exactly 3 live neighbors (reproduction)", () => {
31	    const input: [number, number][] = [[0, 0], [1, 0], [0, 1]];
32	    const result = nextGeneration(input);
33	    expect(new Set(result.map(c => c.join(",")))).toEqual(
34	      new Set([[0, 0], [1, 0], [0, 1], [1, 1]].map(c => c.join(",")))
35	    );
36	  });
37	  it("kills a live cell with more than 3 neighbors (overpopulation)", () => {
38	    // Center cell (1,1) has 4 live neighbors and should die
39	    const input: [number, number][] = [
40	      [0, 0], [1, 0], [2, 0],
41	              [1, 1],
42	      [0, 2],         [2, 2],
43	    ];
44	    const result = nextGeneration(input);
45	    const keys = new Set(result.map(c => c.join(",")));
46	    expect(keys.has("1,1")).toBe(false);
47	  });
48	  it("handles negative coordinates correctly", () => {
49	    // Block at negative coordinates - still life
50	    const block: [number, number][] = [[-1, -1], [0, -1], [-1, 0], [0, 0]];
51	    const result = nextGeneration(block);
52	    expect(new Set(result.map(c => c.join(",")))).toEqual(
53	      new Set(block.map(c => c.join(",")))
54	    );
55	  });
56	});
